UPDATE leads
SET
  evento_schedule = true,
 {{ (() => {
  const f = $item("0").$node["Execute a SQL query2"].json["faturamento"];
  const clean = f ? f.replace(/[*]/g, '').trim() : null;

  const map = { 
      "Ainda não faturo": "C", 
      "Até R$12 mil por mês": "C", 
      "Entre R$13 e R$25 mil por mês": "B",
      "Entre R$25 e R$50 mil por mês": "A",
      "Entre R$50 e R$100 mil por mês": "A",
      "Entre R$100 e R$200 mil por mês": "A",
      "Mais de R$200 mil por mês": "A"
    };

  const faixa = map[clean];

  if (!faixa) {
    return `evento_faxa_a = true, evento_faxa_b = true, evento_faxa_c = true`;
  }

  const result = [];
  if (faixa === "A") result.push("evento_faxa_a = true");
  if (faixa === "B") result.push("evento_faxa_b = true");
  if (faixa === "C") result.push("evento_faxa_c = true");

  return result.join(', ');
})() }}


