const fbc = $item("0").$node["Execute a SQL query3"].json["fbc"];

function isFbcLessThan7Days(fbc) {
  if (!fbc || typeof fbc !== 'string') return false;

  const parts = fbc.split('.');

  // Estrutura esperada: fb.1.timestamp.fbclid
  if (parts.length < 4) return false;
  if (parts[0] !== 'fb') return false;

  const timestamp = Number(parts[2]);
  if (isNaN(timestamp)) return false;

  const now = Date.now();
  const sevenDaysInMs = 90 * 24 * 60 * 60 * 1000;

  return (now - timestamp) <= sevenDaysInMs;
}

return [
  {
    json: {
      fbc_valido_90_dias: isFbcLessThan7Days(fbc)
    }
  }
];
